import { useEffect, useMemo, useState } from 'react';
import { useTable, useSortBy } from 'react-table';
import { getAllStock, addStock, removeStock, transferStock, getEntrepots, getProduits, getMovementsByProduct } from '../services/stockApi';
import { Plus, Minus, ArrowRightLeft, Search, Filter, Pencil, Trash2, Clock, Upload, Download, RefreshCcw } from 'lucide-react';
import Modal from '../components/Modal';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

const STATUS_OK = 'OK';
const STATUS_LOW = 'Bas';
const STATUS_OUT = 'Rupture';

const getStatus = (qty) => {
  if (qty <= 5) return STATUS_OUT;
  if (qty <= 15) return STATUS_LOW;
  return STATUS_OK;
};

const statusClass = (status) => {
  if (status === STATUS_OK) return 'badge badge-green';
  if (status === STATUS_LOW) return 'badge badge-yellow';
  return 'badge badge-red';
};

function StockForm({ mode, produits, entrepots, existing, onSubmit, onCancel, onValueChange }) {
  const [form, setForm] = useState({
    productId: existing?.productId || '',
    warehouseId: existing?.warehouseId || '',
    fromWarehouseId: existing?.warehouseId || '',
    toWarehouseId: existing?.warehouseId || '',
    quantity: existing?.quantity || '',
    note: existing?.note || '',
  });

  const setField = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (onValueChange) onValueChange({ ...form, [key]: value });
  };

  const checkQuantity = (value) => Number(value) > 0 && Number.isFinite(Number(value));

  const validate = () => {
    if (!form.productId) return 'Produit requis';
    if (mode !== 'view' && Number(form.quantity) <= 0) return 'Quantité doit être > 0';
    if ((mode === 'add' || mode === 'remove') && !form.warehouseId) return 'Entrepôt requis';
    if (mode === 'transfer' && form.fromWarehouseId === form.toWarehouseId) return 'Entrepôts source/destination doivent être différents';
    if (mode === 'remove' && Number(form.quantity) > Number(existing?.quantity || 0)) return 'Quantité supérieure au stock disponible';
    return null;
  };

  const actionLabel = mode === 'add' ? 'Ajouter' : mode === 'remove' ? 'Retirer' : mode === 'transfer' ? 'Transférer' : 'Modifier';

  const handleSubmit = async () => {
    const error = validate();
    if (error) return toast.error(error);
    await onSubmit({ ...form, productId: Number(form.productId), quantity: Number(form.quantity), warehouseId: Number(form.warehouseId || 0), fromWarehouseId: Number(form.fromWarehouseId || 0), toWarehouseId: Number(form.toWarehouseId || 0) });
  };

  return (
    <div style={{ display: 'grid', gap: 12 }}>
      <div className="form-group">
        <label>Produit *</label>
        <select value={form.productId} onChange={(e) => setField('productId', e.target.value)}>
          <option value="">— Sélectionner —</option>
          {produits.map((p) => (<option key={p.id} value={p.id}>{p.name}</option>))}
        </select>
      </div>

      <div className="form-group">
        <label>Quantité *</label>
        <input type="number" min="1" value={form.quantity} onChange={(e) => setField('quantity', e.target.value)} />
      </div>

      {(mode === 'add' || mode === 'remove') && (
        <div className="form-group">
          <label>Entrepôt *</label>
          <select value={form.warehouseId} onChange={(e) => setField('warehouseId', e.target.value)}>
            <option value="">— Sélectionner —</option>
            {entrepots.map((e) => (<option key={e.id} value={e.id}>{e.name}</option>))}
          </select>
        </div>
      )}

      {mode === 'transfer' && (
        <div className="form-grid">
          <div className="form-group">
            <label>Source *</label>
            <select value={form.fromWarehouseId} onChange={(e) => setField('fromWarehouseId', e.target.value)}>
              <option value="">— Source —</option>
              {entrepots.map((e) => (<option key={e.id} value={e.id}>{e.name}</option>))}
            </select>
          </div>
          <div className="form-group">
            <label>Destination *</label>
            <select value={form.toWarehouseId} onChange={(e) => setField('toWarehouseId', e.target.value)}>
              <option value="">— Destination —</option>
              {entrepots.map((e) => (<option key={e.id} value={e.id}>{e.name}</option>))}
            </select>
          </div>
        </div>
      )}

      <div className="form-group">
        <label>Motif</label>
        <input value={form.note} onChange={(e) => setField('note', e.target.value)} placeholder="Raison / commentaire" />
      </div>

      <button className="btn btn-primary" style={{ width: '100%' }} onClick={handleSubmit}>{actionLabel}</button>
      <button className="btn btn-ghost" style={{ width: '100%' }} onClick={onCancel}>Annuler</button>
    </div>
  );
}

function exportStockCSV(items) {
  const rows = [
    ['Produit', 'Entrepôt', 'Quantité', 'Prix unitaire', 'Statut'],
    ...items.map((s) => [s.productName, s.warehouseName, s.quantity, s.productPrice || 0, getStatus(s.quantity)]),
  ];
  const csv = rows.map((r) => r.map((c) => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n');
  const url = URL.createObjectURL(new Blob([csv], { type: 'text/csv' }));
  const a = document.createElement('a');
  a.href = url;
  a.download = 'stocks-export.csv';
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

export default function StockList() {
  const [stocks, setStocks] = useState([]);
  const [produits, setProduits] = useState([]);
  const [entrepots, setEntrepots] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null);
  const [selected, setSelected] = useState(null);

  const [search, setSearch] = useState('');
  const [filterWH, setFilterWH] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [filterCategory, setFilterCategory] = useState('');
  const [quantityMin, setQuantityMin] = useState('');
  const [quantityMax, setQuantityMax] = useState('');

  const [viewMode, setViewMode] = useState('table');
  const [page, setPage] = useState(0);
  const pageSize = 10;

  const [isImporting, setIsImporting] = useState(false);

  const load = async () => {
    setLoading(true);
    try {
      const [s, p, e] = await Promise.all([getAllStock(filterWH || undefined), getProduits(), getEntrepots()]);
      setStocks(s.data || []);
      setProduits(p.data || []);
      setEntrepots(e.data || []);
    } catch (err) {
      toast.error('Erreur de chargement');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, [filterWH]);

  const categories = useMemo(() => {
    const cats = new Set();
    stocks.forEach((s) => {
      const cat = s.productName?.split(' ')[0] || 'Autre';
      cats.add(cat);
    });
    return Array.from(cats);
  }, [stocks]);

  const filtered = useMemo(() => {
    const base = stocks.filter((s) => {
      const q = search.toLowerCase();
      if (q && !(`${s.productName} ${s.warehouseName}`.toLowerCase().includes(q))) return false;
      if (filterStatus && getStatus(s.quantity) !== filterStatus) return false;
      if (filterCategory && !(s.productName || '').toLowerCase().startsWith(filterCategory.toLowerCase())) return false;
      if (quantityMin && s.quantity < Number(quantityMin)) return false;
      if (quantityMax && s.quantity > Number(quantityMax)) return false;
      return true;
    });
    setPage(0);
    return base;
  }, [stocks, search, filterStatus, filterCategory, quantityMin, quantityMax]);

  const maxStock = useMemo(() => Math.max(1, ...stocks.map((s) => s.quantity || 0)), [stocks]);
  const totalQuantity = useMemo(() => stocks.reduce((a, v) => a + (v.quantity || 0), 0), [stocks]);
  const totalValue = useMemo(() => stocks.reduce((a, v) => a + ((v.quantity || 0) * Number(v.productPrice || 0)), 0), [stocks]);

  const columns = useMemo(() => [
    { Header: '#', accessor: 'index', Cell: ({ row }) => row.index + 1 },
    { Header: 'Produit', accessor: 'productName' },
    { Header: 'Catégorie', accessor: (row) => row.productName?.split(' ')[0] || 'Autre', id: 'category' },
    { Header: 'Entrepôt', accessor: 'warehouseName' },
    { Header: 'Qté', accessor: 'quantity', Cell: ({ value }) => (
      <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
        <div style={{ width: '100%', height: 10, background: 'rgba(236,72,153,0.18)', borderRadius: 999 }}>
          <div style={{ width: `${Math.round((value / maxStock) * 100)}%`, height: '100%', background: 'linear-gradient(90deg, #ec4899, #db2777)', borderRadius: 999 }} />
        </div>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11 }}>
          <span>{value}</span><span>{Math.round((value / maxStock) * 100)}%</span>
        </div>
      </div>
    )},
    { Header: 'Status', accessor: 'quantity', Cell: ({ value }) => {
      const status = getStatus(value);
      return <span className={statusClass(status)}>{status}</span>;
    } },
    { Header: 'Actions', accessor: 'actions', disableSortBy: true, Cell: ({ row }) => {
      const item = row.original;
      const handleHistory = async () => {
        try {
          const m = await getMovementsByProduct(item.productId);
          toast.success(`Derniers mouvements: ${m.data.length}`);
        } catch (err) {
          toast.error('Impossible de charger l’historique');
        }
      };

      return (
        <div style={{ display: 'flex', gap: 6 }}>
          <button className="btn btn-ghost" title="Modifier" onClick={() => { setSelected(item); setModal('edit'); }}><Pencil size={14} /></button>
          <button className="btn btn-ghost" title="Supprimer" onClick={() => {
            if (!window.confirm('Supprimer cette ligne ?')) return;
            removeStock({ productId: item.productId, warehouseId: item.warehouseId, quantity: item.quantity }).then(() => { toast.success('Supprimé'); load(); }).catch((e) => toast.error(e.message));
          }}><Trash2 size={14} /></button>
          <button className="btn btn-ghost" title="Historique" onClick={handleHistory}><Clock size={14} /></button>
        </div>
      );
    } },
  ], [maxStock]);

  const tableInstance = useTable({ columns, data: filtered }, useSortBy);
  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  const pageCount = Math.max(1, Math.ceil(filtered.length / pageSize));
  const pageRows = useMemo(() => rows.slice(page * pageSize, (page + 1) * pageSize), [rows, page, pageSize]);

  const handleSubmit = async (payload) => {
    try {
      if (modal === 'add') await addStock({ ...payload, productId: Number(payload.productId), warehouseId: Number(payload.warehouseId) });
      else if (modal === 'remove') {
        await removeStock({ productId: Number(payload.productId), warehouseId: Number(payload.warehouseId), quantity: Number(payload.quantity) });
      } else if (modal === 'transfer') await transferStock(payload);
      else if (modal === 'edit') {
        const diff = Number(payload.quantity) - Number(selected.quantity);
        if (diff > 0) await addStock({ ...payload, warehouseId: Number(payload.warehouseId), quantity: diff });
        if (diff < 0) await removeStock({ productId: Number(payload.productId), warehouseId: Number(payload.warehouseId), quantity: -diff });
      }
      toast.success('Opération réussie');
      setModal(null);
      setSelected(null);
      load();
    } catch (err) {
      toast.error(err.message || 'Échec de l’opération');
    }
  };

  const handleImportCSV = (event) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const text = e.target.result;
        const lines = text.split('\n').map((l) => l.trim()).filter(Boolean);
        for (let i = 1; i < lines.length; i += 1) {
          const [product, warehouse, qty] = lines[i].split(',').map((c) => c.replace(/^"|"$/g, '').trim());
          const produit = produits.find((p) => p.name.toLowerCase() === product.toLowerCase());
          const entrep = entrepots.find((w) => w.name.toLowerCase() === warehouse.toLowerCase());
          if (!produit || !entrep) continue;
          await addStock({ productId: produit.id, warehouseId: entrep.id, quantity: Number(qty) });
        }
        toast.success('Import CSV terminé');
        load();
      } catch (err) {
        toast.error('Erreur import CSV');
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  const resetFilters = () => {
    setSearch('');
    setFilterStatus('');
    setFilterCategory('');
    setQuantityMin('');
    setQuantityMax('');
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Stocks</h2>
          <p>Total lignes : {stocks.length} · Qté totale : {totalQuantity} · Valeur : €{totalValue.toFixed(2)}</p>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          <button className="btn btn-success" title="Ajouter" onClick={() => { setSelected(null); setModal('add'); }}><Plus size={15}/> Ajouter</button>
          <button className="btn btn-danger" title="Retirer" onClick={() => { setSelected(null); setModal('remove'); }}><Minus size={15}/> Retirer</button>
          <button className="btn btn-primary" title="Transférer" onClick={() => { setSelected(null); setModal('transfer'); }}><ArrowRightLeft size={15}/> Transférer</button>
          <button className="btn btn-ghost" title="Vue Liste" onClick={() => setViewMode('table')}>Tableau</button>
          <button className="btn btn-ghost" title="Vue Cartes" onClick={() => setViewMode('cards')}>Cartes</button>
          <button className="btn btn-ghost" title="Export CSV" onClick={() => exportStockCSV(filtered)}><Download size={15}/> Export CSV</button>
          <label className="btn btn-ghost" title="Import CSV" style={{ cursor: 'pointer' }}>
            <Upload size={15}/> Import CSV
            <input type="file" accept=".csv" style={{ display: 'none' }} onChange={handleImportCSV} disabled={isImporting} />
          </label>
        </div>
      </div>

      <div className="toolbar" style={{ gap: 10, flexWrap: 'wrap' }}>
        <div className="search-box">
          <Search size={14} />
          <input placeholder="Recherche produit / entrepôt..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)} title="Filtrer par statut">
          <option value="">Tous statuts</option>
          <option value={STATUS_OK}>OK</option>
          <option value={STATUS_LOW}>Bas</option>
          <option value={STATUS_OUT}>Rupture</option>
        </select>
        <select value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)} title="Filtrer par catégorie">
          <option value="">Toutes catégories</option>
          {categories.map((cat) => <option key={cat} value={cat}>{cat}</option>)}
        </select>
        <input type="number" placeholder="Qté min" value={quantityMin} onChange={(e) => setQuantityMin(e.target.value)} style={{ width: 90 }} />
        <input type="number" placeholder="Qté max" value={quantityMax} onChange={(e) => setQuantityMax(e.target.value)} style={{ width: 90 }} />
        <button className="btn btn-ghost" onClick={resetFilters}><RefreshCcw size={14}/> Réinitialiser</button>
      </div>

      {loading ? (
        <div className="skeleton-grid" style={{ gridTemplateColumns: 'repeat(3, minmax(0, 1fr))' }}>
          {[...Array(6)].map((_, i) => <div key={i} className="skeleton-card" style={{ height: 120 }} />)}
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 32, color: 'var(--text-muted)' }}>
          <p style={{ fontSize: 20 }}>📭 Aucun résultat</p>
          <p>Essayez d’ajuster les filtres ou de vider la recherche.</p>
        </div>
      ) : viewMode === 'cards' ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 16 }}>
          {filtered.map((item) => {
            const status = getStatus(item.quantity);
            return (
              <div key={`${item.productId}-${item.warehouseId}`} className="card" style={{ padding: 16 }}>
                <div style={{ fontWeight: 700 }}>{item.productName}</div>
                <div>{item.warehouseName}</div>
                <div>{item.quantity} pcs</div>
                <div className={statusClass(status)}>{status}</div>
                <div style={{ marginTop: 8, display: 'flex', gap: 6 }}>
                  <button className="btn btn-ghost" title="Modifier" onClick={() => { setSelected(item); setModal('edit'); }}><Pencil size={14}/></button>
                  <button className="btn btn-ghost" title="Supprimer" onClick={() => {
                    if (!window.confirm('Supprimer cette ligne ?')) return;
                    removeStock({ productId: item.productId, warehouseId: item.warehouseId, quantity: item.quantity }).then(() => { toast.success('Supprimé'); load(); });
                  }}><Trash2 size={14}/></button>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="overflow-x-auto" style={{ maxWidth: '100%' }}>
          <table {...getTableProps()} className="min-w-full divide-y divide-slate-700" style={{ borderCollapse: 'collapse' }}>
            <thead className="bg-slate-800 text-xs uppercase tracking-wide text-slate-400">
              {headerGroups.map((headerGroup) => (
                <tr {...headerGroup.getHeaderGroupProps()}>
                  {headerGroup.headers.map((column) => (
                    <th {...column.getHeaderProps(column.getSortByToggleProps())} className="px-4 py-3 text-left" style={{ cursor: column.disableSortBy ? 'initial' : 'pointer' }}>
                      {column.render('Header')}
                      <span>{column.isSorted ? (column.isSortedDesc ? ' ↓' : ' ↑') : ''}</span>
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody {...getTableBodyProps()} className="divide-y divide-slate-700 bg-slate-900">
              {pageRows.map((row) => {
                prepareRow(row);
                return (
                  <tr {...row.getRowProps()} className="hover:bg-slate-800" style={{ backgroundColor: row.index % 2 ? 'rgba(255,255,255,0.03)' : 'transparent' }}>
                    {row.cells.map((cell) => (
                      <td {...cell.getCellProps()} className="px-4 py-3 align-top">{cell.render('Cell')}</td>
                    ))}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      <div style={{ marginTop: 12, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span>Page {page + 1} / {pageCount} ({filtered.length} lignes)</span>
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn btn-ghost" onClick={() => setPage((prev) => Math.max(0, prev - 1))} disabled={page === 0}>←</button>
          <button className="btn btn-ghost" onClick={() => setPage((prev) => Math.min(pageCount - 1, prev + 1))} disabled={page >= pageCount - 1}>→</button>
        </div>
      </div>

      {modal && (
        <Modal title={modal === 'add' ? 'Ajouter du stock' : modal === 'remove' ? 'Retirer du stock' : modal === 'transfer' ? 'Transférer du stock' : 'Modifier stock'} onClose={() => { setModal(null); setSelected(null); }}>
          <StockForm mode={modal === 'edit' ? 'edit' : modal} produits={produits} entrepots={entrepots} existing={selected} onSubmit={handleSubmit} onCancel={() => setModal(null)} />
        </Modal>
      )}
    </div>
  );
}
